@import url('https://fonts.googleapis.com/css2?family=Fira+Code:wght@300..700&display=swap');

a {
  display: block;                   /* Make each link take up a full line */
  text-decoration: none;            /* Optional: remove underline */
  padding: 8px;                     /* Add padding inside each link */
  margin: 0;                        /* Remove all margins */
  border: 2px solid transparent;    /* Transparent borders to avoid jumping */
}

a:first-child {
  border-color: #DCD7BA;            /* Apply visible border */
  border-bottom: none;              /* Avoid double bottom border */
  border-radius: 5px 5px 0 0;       /* Round the top corners */
}

a:last-child {
  border-color: #DCD7BA;            /* Apply visible border */
  border-top: none;                 /* Avoid double top border */
  border-radius: 0 0 5px 5px;       /* Round the bottom corners */
}

a:not(:first-child):not(:last-child) {
  border-left-color: #DCD7BA;       /* Left and right borders for middle links */
  border-right-color: #DCD7BA;
  border-top: none;                 /* Remove top border to merge with the link above */
}
